@namespace Lumeo
@implements IAsyncDisposable

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@{
    var displayText = GetDisplayText();
}

@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium text-foreground mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<div id="@_wrapperId" class="relative inline-block @Class" @attributes="AdditionalAttributes">
    <button type="button"
            id="@EffectiveTriggerId"
            class="@TriggerClass"
            @onclick="ToggleOpen"
            disabled="@Disabled"
            aria-haspopup="tree"
            aria-expanded="@_isOpen"
            aria-describedby="@FormFieldDescribedBy"
            aria-required="@(Required ? "true" : "false")"
            aria-invalid="@(EffectiveInvalid ? "true" : "false")">
        <span class="@(Cx.Join("flex-1 truncate text-start", Cx.When(displayText == (Placeholder ?? L["TreeSelect.Placeholder"]), "text-muted-foreground")))">@displayText</span>
        <span class="ms-1 flex shrink-0 items-center gap-1">
            @if (Clearable && !Disabled && HasSelection())
            {
                <span role="button"
                      tabindex="0"
                      class="rounded-[calc(var(--radius)*2)] p-0.5 hover:bg-foreground/20 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                      aria-label="@L["TreeSelect.ClearSelection"]"
                      @onclick="Clear"
                      @onclick:stopPropagation="true"
                      @onkeydown="HandleClearKeyDown"
                      @onkeydown:stopPropagation="true">
                    <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3.5 w-3.5 text-muted-foreground" />
                </span>
            }
            @{ var chevronClass = Cx.Join("h-4 w-4 opacity-50 transition-transform", Cx.When(_isOpen, "rotate-180")); }
            <SvgGlyph Svg="@(LumeoIcons.ChevronDown)" class="@chevronClass" />
        </span>
    </button>

    @if (_isOpen)
    {
        <div id="@_contentId"
             class="fixed z-50 min-w-[12rem] overflow-hidden rounded-md border border-border/40 bg-popover shadow-lg animate-fade-in"
             role="tree"
             aria-multiselectable="@(Multiple ? "true" : null)"
             tabindex="-1"
             @onkeydown="HandleKeyDown">
            @if (Searchable)
            {
                <div class="p-2 border-b border-border/40">
                    <input type="text"
                           class="w-full rounded-md border border-input bg-background px-3 py-1.5 text-sm outline-none placeholder:text-muted-foreground focus:ring-1 focus:ring-ring"
                           placeholder="@L["Combobox.SearchPlaceholder"]"
                           value="@_searchText"
                           @oninput="OnSearchInput"
                           @onkeydown="OnSearchKeyDown"
                           @onkeydown:stopPropagation="true"
                           @onclick:stopPropagation="true" />
                </div>
            }
            <div class="max-h-60 overflow-y-auto p-1">
                @{ _flatVisible = null; }
                @foreach (var item in Items)
                {
                    <div @key="item.Value">@RenderTreeItem(item, 0)</div>
                }
                @if (!HasVisibleItems())
                {
                    <div class="py-4 text-center text-sm text-muted-foreground">@L["TreeSelect.NoResults"]</div>
                }
            </div>
        </div>
    }
</div>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive mt-1.5">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground mt-1.5">@HelperText</p>
    }
}
</div>

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    // aria-describedby on the trigger announces the FormField help/error to a screen
    // reader.
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Inside a FormField, adopt its ControlId as the trigger button's id so the
    // field's <Label For> actually click-focuses the tree select (Base UI Field parity,
    // matching Select/Textarea/DatePicker/TimePicker). Standalone, keep our own generated id.
    // Every internal id use (the rendered id attribute, restore-focus on close) flows
    // through this so the rendered id and the focus target stay consistent.
    private string EffectiveTriggerId =>
        !string.IsNullOrEmpty(FormField?.ControlId) ? FormField!.ControlId : _triggerId;

    /// <summary>The selected node's value (single-select mode). Use <see cref="Values"/>
    /// instead when <see cref="Multiple"/> is true.</summary>
    [Parameter] public string? Value { get; set; }
    /// <summary>Fired when the selected node changes (single-select mode). Binding it
    /// makes <see cref="Value"/> controlled.</summary>
    [Parameter] public EventCallback<string> ValueChanged { get; set; }
    /// <summary>The hierarchical node tree rendered in the dropdown.</summary>
    [Parameter] public List<TreeSelectItem> Items { get; set; } = new();
    /// <summary>Placeholder shown in the trigger when nothing is selected. Defaults to the
    /// localized "TreeSelect.Placeholder" string.</summary>
    [Parameter] public string? Placeholder { get; set; }
    /// <summary>Shows a search box at the top of the dropdown that filters nodes by label,
    /// auto-expanding ancestors of every match.</summary>
    [Parameter] public bool Searchable { get; set; }
    /// <summary>Enables multi-select mode: any node (leaf or parent) toggles into
    /// <see cref="Values"/> on click, and <c>aria-checked</c> reflects tri-state
    /// selection for parents with partially-selected descendants.</summary>
    [Parameter] public bool Multiple { get; set; }
    /// <summary>The selected node values (multi-select mode, used when
    /// <see cref="Multiple"/> is true).</summary>
    [Parameter] public List<string>? Values { get; set; }
    /// <summary>Fired when the selection changes in multi-select mode. Binding it makes
    /// <see cref="Values"/> controlled.</summary>
    [Parameter] public EventCallback<List<string>?> ValuesChanged { get; set; }
    /// <summary>Disables the trigger, preventing the dropdown from opening.</summary>
    [Parameter] public bool Disabled { get; set; }
    /// <summary>Expands every node with children when the tree first renders (and whenever
    /// <see cref="Items"/> is replaced with a new reference).</summary>
    [Parameter] public bool ExpandAll { get; set; }
    /// <summary>Shows a clear button in the trigger when a selection exists, letting the
    /// user reset <see cref="Value"/>/<see cref="Values"/> in one click.</summary>
    [Parameter] public bool Clearable { get; set; }
    /// <summary>Marks the field as required, rendering an asterisk next to <see cref="Label"/>
    /// and setting <c>aria-required</c> on the trigger.</summary>
    [Parameter] public bool Required { get; set; }
    /// <summary>Forces the invalid/error visual state on the trigger. Also set implicitly
    /// when a wrapping <c>FormField</c> reports a validation error.</summary>
    [Parameter] public bool Invalid { get; set; }
    /// <summary>Error message shown below the field when <see cref="Invalid"/> is true
    /// (and the tree select is not nested inside a <c>FormField</c>).</summary>
    [Parameter] public string? ErrorText { get; set; }
    /// <summary>Helper text shown below the field when there is no error (and the tree
    /// select is not nested inside a <c>FormField</c>).</summary>
    [Parameter] public string? HelperText { get; set; }
    /// <summary>Label rendered above the trigger. Suppressed when nested inside a
    /// <c>FormField</c>, which renders its own label instead.</summary>
    [Parameter] public string? Label { get; set; }
    /// <summary>The form field name, forwarded for consistency with other form controls
    /// (not rendered directly by this component).</summary>
    [Parameter] public string? Name { get; set; }
    /// <summary>Additional CSS classes merged onto the wrapper <c>div</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the wrapper <c>div</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    private readonly string _wrapperId = LumeoIds.New("treeselect");
    private readonly string _triggerId = LumeoIds.New("treeselect-trigger");
    private readonly string _contentId = LumeoIds.New("treeselect-content");
    private bool _isOpen;
    private bool _registered;
    private bool _disposed;
    private string _searchText = "";
    private readonly HashSet<string> _expandedNodes = new();
    private List<TreeSelectItem>? _previousItems;

    // Roving tabindex / WAI-ARIA tree keyboard navigation state. Exactly one
    // visible treeitem is tabbable (_activeItem); the rest are reachable via
    // arrow keys. _flatVisible is the depth-first list of currently-visible
    // nodes, rebuilt lazily (invalidated on every render of the panel body).
    private readonly Dictionary<string, string> _nodeIds = new();
    private List<TreeSelectItem>? _flatVisible;
    // Roving focus is anchored by stable identity (the active node's Value), not
    // by object reference. _activeItem is the resolved node for the CURRENT
    // Items render; it is re-resolved from _activeValue in EnsureFlatVisible so
    // an equal-content Items replacement (new instances, same Values — e.g. an
    // async refresh) keeps focus on the same logical node instead of snapping
    // back to the first one. This mirrors how _expandedNodes is keyed by Value.
    private TreeSelectItem? _activeItem;
    private string? _activeValue;

    private string TriggerClass =>
        $"flex h-9 w-full items-center justify-between rounded-md border {(EffectiveInvalid ? "border-destructive" : "border-input")} bg-background px-3 py-2 text-sm shadow-sm transition-colors disabled:cursor-not-allowed disabled:opacity-50 hover:bg-accent/50 focus:outline-none focus:ring-1 {(EffectiveInvalid ? "focus:ring-destructive/20" : "focus:ring-ring")}".Trim();

    // ExpandAll must re-apply when Items arrive/replace asynchronously — the
    // original OnInitialized-only pass never ran for late-bound data, so an
    // async tree never auto-expanded. Track the Items reference and re-expand
    // whenever it changes.
    protected override void OnParametersSet()
    {
        if (ExpandAll && !ReferenceEquals(Items, _previousItems))
        {
            ExpandAllNodes(Items);
        }
        _previousItems = Items;
    }

    private void ExpandAllNodes(List<TreeSelectItem> items)
    {
        foreach (var item in items)
        {
            if (item.Children?.Count > 0)
            {
                _expandedNodes.Add(item.Value);
                ExpandAllNodes(item.Children);
            }
        }
    }

    private string GetDisplayText()
    {
        var placeholder = Placeholder ?? L["TreeSelect.Placeholder"];
        if (Multiple)
        {
            if (Values == null || Values.Count == 0) return placeholder;
            var labels = Values.Select(v => FindLabel(Items, v)).Where(l => l != null).ToList();
            return labels.Count > 0 ? string.Join(", ", labels) : placeholder;
        }
        if (string.IsNullOrEmpty(Value)) return placeholder;
        return FindLabel(Items, Value) ?? placeholder;
    }

    private string? FindLabel(List<TreeSelectItem> items, string value)
    {
        foreach (var item in items)
        {
            if (item.Value == value) return item.Label;
            if (item.Children?.Count > 0)
            {
                var found = FindLabel(item.Children, value);
                if (found != null) return found;
            }
        }
        return null;
    }

    private bool HasVisibleItems() => Items.Any(i => IsVisible(i));

    private bool IsVisible(TreeSelectItem item)
    {
        if (string.IsNullOrEmpty(_searchText)) return true;
        if (item.Label.Contains(_searchText, StringComparison.OrdinalIgnoreCase)) return true;
        return item.Children?.Any(IsVisible) == true;
    }

    private bool MatchesSearch(TreeSelectItem item) =>
        string.IsNullOrEmpty(_searchText) ||
        item.Label.Contains(_searchText, StringComparison.OrdinalIgnoreCase);

    private bool IsSelected(string value)
    {
        if (Multiple) return Values?.Contains(value) == true;
        return Value == value;
    }

    private async Task SelectItem(TreeSelectItem item)
    {
        if (item.Disabled) return;

        if (Multiple)
        {
            var current = Values ?? new List<string>();
            if (current.Contains(item.Value))
                current = current.Where(v => v != item.Value).ToList();
            else
                current = new List<string>(current) { item.Value };
            Values = current.Count > 0 ? current : null;
            await ValuesChanged.InvokeAsync(Values);
        }
        else
        {
            Value = item.Value;
            await ValueChanged.InvokeAsync(item.Value);
            await CloseDropdown(restoreFocus: true);
        }
    }

    private void ToggleNode(string value)
    {
        if (_expandedNodes.Contains(value))
            _expandedNodes.Remove(value);
        else
            _expandedNodes.Add(value);
    }

    private async Task ToggleOpen()
    {
        if (_isOpen)
            await CloseDropdown();
        else
            await OpenDropdown();
    }

    private async Task OpenDropdown()
    {
        _isOpen = true;
        _searchText = "";
        // Seed the roving focus on the first selected node if one is visible,
        // otherwise the first node; the panel itself takes focus so arrow keys
        // are handled even before a treeitem is focused. Seed BEFORE the first open
        // render so the selected node is the tab stop immediately (no flash of the
        // first node, and no dependency on the post-interop re-render below).
        _flatVisible = null;
        SeedActiveFromSelection();
        StateHasChanged();
        await Task.Yield();
        if (_disposed) return;
        await Interop.PositionFixed(_contentId, _wrapperId, "start", true, "bottom");
        // Mark registered as soon as the first global registration lands so
        // CloseDropdown/DisposeAsync actually run UnpositionFixed / UnregisterClickOutside /
        // UnregisterPreventDefaultKeys. Previously this flag was never set after open, so
        // every close short-circuited teardown and leaked the global registrations.
        _registered = true;
        if (_disposed) return;
        await Interop.RegisterClickOutside(_contentId, _wrapperId, async () =>
        {
            await CloseDropdown();
            await InvokeAsync(StateHasChanged);
        });
        if (_disposed) return;
        // Suppress the browser default (page/overflow scroll) for the tree
        // navigation keys, scoped to the panel. SkipEditable keeps the search
        // input's own caret/typing keys alive.
        try
        {
            await Interop.RegisterPreventDefaultKeys(_contentId, new[]
            {
                new Lumeo.Services.PreventDefaultKeyRule("ArrowDown", SkipEditable: true),
                new Lumeo.Services.PreventDefaultKeyRule("ArrowUp", SkipEditable: true),
                new Lumeo.Services.PreventDefaultKeyRule("ArrowLeft", SkipEditable: true),
                new Lumeo.Services.PreventDefaultKeyRule("ArrowRight", SkipEditable: true),
                new Lumeo.Services.PreventDefaultKeyRule("Home", SkipEditable: true),
                new Lumeo.Services.PreventDefaultKeyRule("End", SkipEditable: true),
            });
        }
        catch (JSDisconnectedException) { }
        if (_disposed) return;
        // Place roving focus on the first VISIBLE selected node so a keyboard user
        // lands on what they previously chose. SeedActiveFromSelection sets
        // _activeValue and invalidates _flatVisible; EnsureFlatVisible then rebuilds
        // and re-resolves _activeItem against it, falling back to the first node
        // only when the selection is absent/not visible. The StateHasChanged pushes
        // the new roving tabindex (0 on the selected node) into the markup — the
        // first open render already ran EnsureFlatVisible with no selection, so
        // without this re-render the tabindex would stay on node 0.
        SeedActiveFromSelection();
        EnsureFlatVisible();
        StateHasChanged();
        if (_activeItem is not null)
        {
            try { await Interop.FocusElement(GetNodeId(_activeItem)); } catch (JSDisconnectedException) { }
        }
        else
        {
            try { await Interop.FocusElement(_contentId); } catch (JSDisconnectedException) { }
        }
    }

    private async Task CloseDropdown(bool restoreFocus = false)
    {
        _isOpen = false;
        // Reset the roving-focus anchor so the NEXT open re-seeds deterministically
        // from the current selection (OpenDropdown -> SeedActiveFromSelection) instead
        // of reusing the node that happened to be active when this session closed.
        _activeItem = null;
        _activeValue = null;
        if (_registered)
        {
            try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
            try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
            try { await Interop.UnregisterPreventDefaultKeys(_contentId); } catch (JSDisconnectedException) { }
            _registered = false;
        }
        // Escape / Enter close: return focus to the trigger so keyboard users
        // aren't stranded (the panel that held focus is now gone).
        if (restoreFocus && !_disposed)
        {
            try { await Interop.FocusElement(EffectiveTriggerId); } catch (JSDisconnectedException) { }
        }
    }

    private void OnSearchInput(ChangeEventArgs e)
    {
        _searchText = e.Value?.ToString() ?? "";
        if (!string.IsNullOrEmpty(_searchText))
        {
            // Auto-expand all when searching
            ExpandAllNodes(Items);
        }
    }

    // ARIA: trees that allow multiple selection should expose aria-checked
    // (with a "mixed" tristate when some descendants are selected) rather
    // than aria-selected, per WAI-ARIA tree pattern §3.40. Single-select
    // trees continue to use aria-selected.
    //
    // The tristate is descendant-aware: a parent with hasChildren reports
    // "true" when every leaf under it is selected, "false" when none, and
    // "mixed" when some are. Without this, screen-reader users only hear
    // the parent's own selection state — which the component never sets,
    // because in Multiple mode only leaves are selectable.
    private string? GetAriaCheckedString(TreeSelectItem item, bool hasChildren)
    {
        if (!Multiple) return null;
        if (!hasChildren) return IsSelected(item.Value) ? "true" : "false";

        int selected = 0, total = 0;
        CountLeafSelection(item, ref selected, ref total);
        if (total == 0) return "false";
        if (selected == 0) return "false";
        if (selected == total) return "true";
        return "mixed";
    }

    private void CountLeafSelection(TreeSelectItem item, ref int selected, ref int total)
    {
        if (item.Children is { Count: > 0 })
        {
            foreach (var child in item.Children) CountLeafSelection(child, ref selected, ref total);
        }
        else
        {
            total++;
            if (IsSelected(item.Value)) selected++;
        }
    }

    private RenderFragment RenderTreeItem(TreeSelectItem item, int depth) => __builder =>
    {
        if (!IsVisible(item)) return;

        var hasChildren = item.Children?.Count > 0;
        var isExpanded = _expandedNodes.Contains(item.Value);
        var isSelected = IsSelected(item.Value);
        var isLeaf = !hasChildren;
        var paddingLeft = depth * 16 + 8;
        // In Multiple mode every node (leaf OR parent) is selectable, so the
        // selected highlight + check mark apply to parents too.
        var showSelected = isSelected && (isLeaf || Multiple);

        <div role="treeitem"
             id="@GetNodeId(item)"
             tabindex="@GetTabIndex(item)"
             aria-selected="@(Multiple ? null : isSelected.ToString().ToLowerInvariant())"
             aria-checked="@GetAriaCheckedString(item, hasChildren)"
             aria-expanded="@(hasChildren ? isExpanded.ToString().ToLowerInvariant() : null)"
             aria-level="@(depth + 1)">
            <div class="@GetItemClass(showSelected, item.Disabled)"
                 style="padding-left: @(paddingLeft)px"
                 @onclick="() => HandleItemClick(item, hasChildren)"
                 @onclick:stopPropagation="true">
                @if (hasChildren)
                {
                    <button type="button"
                            class="me-1 rounded hover:bg-accent p-0.5 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1"
                            tabindex="-1"
                            aria-label="@L[isExpanded ? "Common.Collapse" : "Common.Expand"]"
                            @onclick="() => ToggleNode(item.Value)"
                            @onclick:stopPropagation="true">
                        @{ var chevronRightClass = Cx.Join("h-3.5 w-3.5 transition-transform", Cx.When(isExpanded, "rotate-90")); }
                        <SvgGlyph Svg="@(LumeoIcons.ChevronRight)" class="@chevronRightClass" />
                    </button>
                }
                else
                {
                    <span class="me-1 w-5 shrink-0"></span>
                }

                @if (!string.IsNullOrEmpty(item.Icon))
                {
                    <span class="me-1.5 text-muted-foreground text-xs">@item.Icon</span>
                }

                <span class="flex-1 truncate text-sm">@item.Label</span>

                @if (showSelected)
                {
                    <SvgGlyph Svg="@(LumeoIcons.Check)" class="h-4 w-4 text-primary shrink-0" />
                }
            </div>

            @if (hasChildren && isExpanded)
            {
                <div role="group">
                    @foreach (var child in item.Children!)
                    {
                        <div @key="child.Value">@RenderTreeItem(child, depth + 1)</div>
                    }
                </div>
            }
        </div>
    };

    // Clicking a row: in single-select a parent expands and a leaf selects.
    // In Multiple mode every node is selectable (AntD's default checkable
    // behavior), so a parent click toggles its own value into the selection;
    // the chevron button (separate hit target) still drives expand/collapse.
    private async Task HandleItemClick(TreeSelectItem item, bool hasChildren)
    {
        _activeItem = item;
        _activeValue = item.Value;
        if (hasChildren && !Multiple)
            ToggleNode(item.Value);
        else
            await SelectItem(item);
    }

    // ---- Clear ----

    private bool HasSelection() => Multiple ? Values is { Count: > 0 } : !string.IsNullOrEmpty(Value);

    private async Task Clear()
    {
        if (Multiple)
        {
            if (Values is null || Values.Count == 0) return;
            Values = null;
            await ValuesChanged.InvokeAsync(null);
        }
        else
        {
            if (string.IsNullOrEmpty(Value)) return;
            Value = null;
            await ValueChanged.InvokeAsync(null!);
        }
    }

    private async Task HandleClearKeyDown(KeyboardEventArgs e)
    {
        if (e.Key is "Enter" or " ") await Clear();
    }

    // ---- WAI-ARIA tree keyboard navigation (roving tabindex) ----
    // Mirrors the TreeView pattern: Down/Up move through visible nodes in
    // depth-first order, Home/End jump to first/last, Right expands then
    // descends, Left collapses then ascends, Enter/Space selects (or expands a
    // parent in single mode), Escape closes and restores focus to the trigger.

    /// <summary>Deterministic per-node element id, stable for the component's
    /// lifetime, used as the focus target for keyboard navigation.</summary>
    private string GetNodeId(TreeSelectItem item)
    {
        if (!_nodeIds.TryGetValue(item.Value, out var id))
        {
            id = $"{_contentId}-node-{_nodeIds.Count}";
            _nodeIds[item.Value] = id;
        }
        return id;
    }

    /// <summary>Roving tabindex: exactly one visible node is in the tab order.</summary>
    private int GetTabIndex(TreeSelectItem item)
    {
        EnsureFlatVisible();
        return item.Value == _activeValue ? 0 : -1;
    }

    /// <summary>On open, anchor the roving focus to the first VISIBLE selected node
    /// (single: Value; multiple: any value in Values) by setting _activeValue, so
    /// EnsureFlatVisible resolves it to that node. Leaves _activeValue untouched when
    /// nothing is selected/visible so the existing flat[0] fallback applies.</summary>
    private void SeedActiveFromSelection()
    {
        var flat = new List<TreeSelectItem>();
        AppendVisible(Items, flat);
        var selected = flat.FirstOrDefault(i => IsSelected(i.Value));
        if (selected is not null && _activeValue != selected.Value)
        {
            _activeValue = selected.Value;
            // Force EnsureFlatVisible to rebuild and re-resolve _activeItem against
            // the new anchor; the open render may already have populated _flatVisible
            // (seeded to the first node) and would otherwise short-circuit.
            _flatVisible = null;
        }
    }

    private void EnsureFlatVisible()
    {
        if (_flatVisible is not null) return;
        _flatVisible = new List<TreeSelectItem>();
        AppendVisible(Items, _flatVisible);
        // Re-anchor the active node by Value, not object reference: after an
        // equal-content Items refresh the previous _activeItem is a stale
        // instance, so prefer the new node carrying the same Value and only fall
        // back to the first visible node when that Value is genuinely gone.
        _activeItem = _flatVisible.FirstOrDefault(i => i.Value == _activeValue)
                      ?? (_flatVisible.Count > 0 ? _flatVisible[0] : null);
        _activeValue = _activeItem?.Value;
    }

    private void AppendVisible(List<TreeSelectItem> items, List<TreeSelectItem> result)
    {
        foreach (var item in items)
        {
            if (!IsVisible(item)) continue;
            result.Add(item);
            if (item.Children is { Count: > 0 } && _expandedNodes.Contains(item.Value))
                AppendVisible(item.Children, result);
        }
    }

    private static TreeSelectItem? FindParent(List<TreeSelectItem> items, TreeSelectItem child)
    {
        foreach (var item in items)
        {
            if (item.Children is not { Count: > 0 }) continue;
            if (item.Children.Any(c => ReferenceEquals(c, child))) return item;
            var found = FindParent(item.Children, child);
            if (found is not null) return found;
        }
        return null;
    }

    // Keydown from the search box: caret-movement keys (and typing a space) stay
    // with the input; the rest (Escape to close, Up/Down to move the active node,
    // Enter to select/expand) drive the tree. Propagation to the panel's
    // HandleKeyDown is stopped on the input so each key is handled exactly once —
    // without this, ArrowLeft/Right/Home/End in the search box also moved or
    // collapsed/expanded tree nodes while editing the query.
    private async Task OnSearchKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowLeft":
            case "ArrowRight":
            case "Home":
            case "End":
            case " ":
                return; // belongs to the text box (caret move / space)
            default:
                await HandleKeyDown(e);
                return;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
        {
            await CloseDropdown(restoreFocus: true);
            return;
        }

        EnsureFlatVisible();
        var flat = _flatVisible!;
        if (flat.Count == 0) return;

        // No active node yet (panel had focus): act on the first node.
        var current = _activeItem ?? flat[0];
        var hasChildren = current.Children is { Count: > 0 };
        var isExpanded = _expandedNodes.Contains(current.Value);

        switch (e.Key)
        {
            case "Enter":
            case " ":
                await HandleItemClick(current, hasChildren);
                return;

            case "ArrowRight":
                if (hasChildren && !isExpanded)
                {
                    _expandedNodes.Add(current.Value);
                    _flatVisible = null;
                    StateHasChanged();
                }
                else if (hasChildren && isExpanded)
                {
                    await MoveActiveTo(current.Children!.FirstOrDefault(IsVisible));
                }
                return;

            case "ArrowLeft":
                if (hasChildren && isExpanded)
                {
                    _expandedNodes.Remove(current.Value);
                    _flatVisible = null;
                    StateHasChanged();
                }
                else
                {
                    await MoveActiveTo(FindParent(Items, current));
                }
                return;

            case "ArrowDown":
            {
                var idx = flat.FindIndex(i => i.Value == current.Value);
                await MoveActiveTo(idx >= 0 && idx < flat.Count - 1 ? flat[idx + 1] : null);
                return;
            }

            case "ArrowUp":
            {
                var idx = flat.FindIndex(i => i.Value == current.Value);
                await MoveActiveTo(idx > 0 ? flat[idx - 1] : null);
                return;
            }

            case "Home":
                await MoveActiveTo(flat[0]);
                return;

            case "End":
                await MoveActiveTo(flat[^1]);
                return;
        }
    }

    private async Task MoveActiveTo(TreeSelectItem? target)
    {
        if (target is null || target.Value == _activeValue) return;
        _activeItem = target;
        _activeValue = target.Value;
        StateHasChanged();
        try { await Interop.FocusElement(GetNodeId(target)); } catch (JSDisconnectedException) { }
    }

    private string GetItemClass(bool showSelected, bool disabled) => Cx.Join(
        "flex items-center gap-1 rounded-md py-1.5 pe-2 cursor-pointer transition-colors",
        disabled ? "opacity-50 cursor-not-allowed" : showSelected ? "bg-accent text-accent-foreground" : "hover:bg-accent/60");

    public async ValueTask DisposeAsync()
    {
        _disposed = true;
        if (_registered)
        {
            try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
            try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
            try { await Interop.UnregisterPreventDefaultKeys(_contentId); } catch (JSDisconnectedException) { }
        }
    }

    public class TreeSelectItem
    {
        public string Label { get; set; } = "";
        public string Value { get; set; } = "";
        public List<TreeSelectItem>? Children { get; set; }
        public bool Disabled { get; set; }
        public string? Icon { get; set; }
    }
}
